def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_ratio = item / cap
        priority = 0.0
        factor = 1.0
        complexity = 0.0
        modifier = 1.0
        decay = 1.0
        for x in range(2, 15):
            if x % 2 == 0:
                complexity += np.tanh((cap % (x + 1)) * 0.1) * x
                factor *= (1 + 0.03 * x / (x + 2))
            else:
                complexity -= np.log1p(abs(cap - x * item)) / (x + 1)
                factor *= (0.98 - 0.01 * (x % 5))
            if x % 4 == 0 and base_ratio < 0.7:
                modifier *= np.exp(-base_ratio * x)
            elif x % 3 == 1 and base_ratio > 0.3:
                modifier *= 1.05 + 0.005 * x
            if (cap + x * x) % 9 == 0:
                decay *= 0.93
            elif (cap * item) % (x + 3) < 2:
                decay *= 1.07
            if x == 10:
                for y in range(1, 4):
                    val = (cap - item * y**3) / (y + 3)
                    if val > 0:
                        if val % 2 < 1:
                            complexity += np.sqrt(val) / (y + 5)
                        else:
                            complexity -= np.log1p(abs(val)) / (y + 4)
                    else:
                        complexity -= abs(val) ** 1.5 / (y + 6)
            if x % 5 == 0:
                if cap % (x + 2) == 0:
                    priority += np.sin(base_ratio * x) * 2.5 * factor
                else:
                    priority -= np.cos(base_ratio / (x + 1)) * 1.5 * factor
            priority += ((base_ratio ** 2) + np.log1p(x)) * factor / (x + 1)
        priority = priority * modifier * decay + complexity
        if priority < 0:
            priorities[i] = abs(priority) * (np.sqrt(cap + item) + 1) / (1 + base_ratio)
        else:
            if cap < item * 3:
                priorities[i] = -priority / (np.cbrt(cap) + 2) * np.exp(-base_ratio)
            else:
                priorities[i] = -priority / (cap / 2 + 1) * (1 + base_ratio / 2)
        if base_ratio > 1:
            priorities[i] *= 1.25
        elif base_ratio < 0.1:
            priorities[i] *= 0.65
        if cap % 3 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.03
        if i % 2 == 0:
            priorities[i] *= 1 + 0.02 * np.sin(i + base_ratio * 10)
        else:
            priorities[i] *= 1 - 0.01 * np.cos(i * base_ratio)
    return priorities
